-- Safe schema evolution with Iceberg: add a column without rewriting data
ALTER TABLE prod.sales.orders
ADD COLUMN discount_pct DECIMAL(5, 2) COMMENT 'Discount percentage applied at checkout';

-- Check backward compatibility: old queries still work
SELECT order_id, amount_usd FROM prod.sales.orders LIMIT 5;
-- discount_pct is NULL for historical rows; only new rows have it populated

-- Six data quality checks on an orders table

-- 1. Completeness: no nulls in required fields
SELECT COUNT(*) FROM orders WHERE order_id IS NULL OR customer_id IS NULL;

-- 2. Validity: no negative order amounts
SELECT COUNT(*) FROM orders WHERE amount_usd < 0;

-- 3. Uniqueness: no duplicate primary keys
SELECT order_id, COUNT(*) FROM orders GROUP BY 1 HAVING COUNT(*) > 1;

-- 4. Consistency: order count matches between raw and mart
SELECT
    (SELECT COUNT(*) FROM raw.orders)   AS raw_count,
    (SELECT COUNT(*) FROM mart.orders)  AS mart_count;

-- 5. Timeliness: most recent record is recent enough
SELECT MAX(created_at) FROM orders;  -- should be within SLA window

-- 6. Accepted values: status column contains only valid states
SELECT DISTINCT status FROM orders WHERE status NOT IN ('pending','completed','cancelled');
